const toLocale = (lang: 'en' | 'pl') => (c: PackCard): LadderPackCard => ({
    id: c.id,
    prompt: c.question[lang],
    options: c.options.map(o => o[lang]),
    correctIndex: c.correctIndex,
    hint: c.hint[lang],
    difficulty: c.difficulty,
});

export const lostCivilizationsEn: LadderPackCard[] = cards.map(toLocale('en'));
export const lostCivilizationsPl: LadderPackCard[] = cards.map(toLocale('pl'));
